import React, { useEffect, useState } from 'react'
import {
  CAvatar,
  CBadge,
  CButton,
  CCollapse,
  CSmartTable,
} from '@coreui/react-pro'

const getBadge = (status) => {
  switch (status) {
    case 'Active':
      return 'success'
    case 'Inactive':
      return 'secondary'
    case 'Pending':
      return 'warning'
    case 'Banned':
      return 'danger'
    default:
      return 'primary'
  }
}

const Colleges = () => {
  const [details, setDetails] = useState([])

  useEffect(() => {
    window.scrollTo(0, 0)
  }, [])

  const toggleDetails = (id) => {
    setDetails((prevDetails) =>
      prevDetails.includes(id)
        ? prevDetails.filter((d) => d !== id)
        : [...prevDetails, id]
    )
  }

  const columns = [
    { key: 'avatar', label: '', filter: false, sorter: false },
    { key: 'name', _style: { width: '20%' } },
    {
      key: 'registered',
      sorter: (a, b) => new Date(a.registered) - new Date(b.registered),
    },
    { key: 'role', _style: { width: '20%' } },
    'status',
    {
      key: 'show_details',
      label: '',
      _style: { width: '1%' },
      filter: false,
      sorter: false,
    },
  ]

  const items = [
    {
      id: 1,
      name: 'Samppa Nori',
      avatar: '1.jpg',
      registered: '2021/03/01',
      role: 'Member',
      status: 'Active',
    },
    {
      id: 2,
      name: 'Estavan Lykos',
      avatar: '2.jpg',
      registered: '2018/02/07',
      role: 'Staff',
      status: 'Inactive',
    },
    {
      id: 3,
      name: 'Chetan Mohamed',
      avatar: '3.jpg',
      registered: '2020/01/15',
      role: 'Admin',
      status: 'Pending',
    },
    {
      id: 4,
      name: 'Derick Maximinus',
      avatar: '4.jpg',
      registered: '2019/04/05',
      role: 'Member',
      status: 'Active',
    },
    {
      id: 5,
      name: 'Friderik Dávid',
      avatar: '5.jpg',
      registered: '2022/03/25',
      role: 'Staff',
      status: 'Banned',
    },
  ]

  return (
    <div className="p-3">
      <CSmartTable
        columns={columns}
        items={items}
        columnFilter
        columnSorter
        footer
        pagination
        itemsPerPage={5}
        itemsPerPageSelect
        clickableRows
        tableFilter
        cleaner
        selectable
        activePage={1}
        sorterValue={{ column: 'status', state: 'asc' }}
        tableProps={{
          className: 'add-this-custom-class',
          responsive: true,
          striped: true,
          hover: true,
        }}
        tableBodyProps={{
          className: 'align-middle',
        }}
        scopedColumns={{
          avatar: (item) => (
            <td>
              <CAvatar src={`../../images/avatars/${item.avatar}`} />
            </td>
          ),
          registered: (item) => {
            const date = new Date(item.registered)
            return (
              <td>
                {date.toLocaleDateString('en-US', {
                  year: 'numeric',
                  month: 'long',
                  day: 'numeric',
                })}
              </td>
            )
          },
          status: (item) => (
            <td>
              <CBadge color={getBadge(item.status)}>{item.status}</CBadge>
            </td>
          ),
          show_details: (item) => (
            <td className="py-2">
              <CButton
                color="primary"
                variant="outline"
                shape="square"
                size="sm"
                onClick={() => toggleDetails(item.id)}
              >
                {details.includes(item.id) ? 'Hide' : 'Show'}
              </CButton>
            </td>
          ),
          details: (item) => (
            <CCollapse visible={details.includes(item.id)}>
              <div className="p-3">
                <h4>{item.name}</h4>
                <p className="text-body-secondary">
                  User since: {new Date(item.registered).toLocaleDateString()}
                </p>
                <CButton size="sm" color="info">
                  User Settings
                </CButton>
                <CButton size="sm" color="danger" className="ms-1">
                  Delete
                </CButton>
              </div>
            </CCollapse>
          ),
        }}
      />
    </div>
  )
}

export default Colleges
